@prefix cdi: <http://ddialliance.org/Specification/DDI-CDI/1.0/RDF/> .
@prefix cdif: <https://cdif.org/0.1/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ a cdi:LongStructureDataSet ] ;
            sh:resultMessage "A LongStructureDataSet should have physical mappings (cdif:hasPhysicalMapping) linking variables to columns." ;
            sh:resultPath cdif:hasPhysicalMapping ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "A LongStructureDataSet should have physical mappings (cdif:hasPhysicalMapping) linking variables to columns." ;
                    sh:minCount 1 ;
                    sh:path cdif:hasPhysicalMapping ;
                    sh:severity sh:Warning ] ] .

@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms true .

